%% function that puts te values in the array
function[true_array] = get_array(array)
    true_array = [0];
    for i = 1:length(array)
        num_indicies = array(2,i);
        value = array(1,i);
        for j = 1:num_indicies
            true_array(end+1) = value;
        end
    end       
 end
